const ranksRaw = $('Semrush Domain Ranks').first().json.data;
const keywordsRaw = $('Semrush Keyword Rankings').first().json.data;

const rankLines = ranksRaw.trim().split('\n');
const rankHeaders = rankLines[0].split(';');
const rankValues = rankLines[1] ? rankLines[1].split(';') : [];

const rankObj = {};
rankHeaders.forEach((h, i) => { rankObj[h.trim()] = rankValues[i] ? rankValues[i].trim() : ''; });

const domainRank = rankObj['Rank'] || rankObj['rank'] || '';
const organicTraffic = rankObj['OrganicTraffic'] || rankObj['Organic Traffic'] || '';
const organicKeywords = rankObj['OrganicKeywords'] || rankObj['Organic Keywords'] || '';

const kwLines = keywordsRaw.trim().split('\n');
const kwHeaders = kwLines[0].split(';');

const keywords = [];
for (let i = 1; i < kwLines.length; i++) {
  if (!kwLines[i].trim()) continue;
  const vals = kwLines[i].split(';');
  const kwObj = {};
  kwHeaders.forEach((h, j) => { kwObj[h.trim()] = vals[j] ? vals[j].trim() : ''; });
  keywords.push({
    keyword: kwObj['Keyword'] || '',
    position: kwObj['Position'] || '',
    searchVolume: kwObj['Search Volume'] || kwObj['Volume'] || ''
  });
}

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    date: today,
    domainRank: domainRank,
    organicTraffic: organicTraffic,
    organicKeywords: organicKeywords,
    keywords: keywords
  }
}];

const metrics = $('Parse Domain Metrics').first().json;
const sheetRows = $input.all();

let previousRank = null;
let rankChange = 'N/A (first run)';
let rankChangeNum = 0;

if (sheetRows && sheetRows.length > 0) {
  for (let i = sheetRows.length - 1; i >= 0; i--) {
    const row = sheetRows[i].json;
    const rankVal = row['Domain Rank'] || row['domain_rank'] || row['DomainRank'];
    if (rankVal && !isNaN(parseInt(rankVal))) {
      previousRank = parseInt(rankVal);
      break;
    }
  }
}

const currentRank = parseInt(metrics.domainRank) || 0;

if (previousRank !== null && currentRank > 0) {
  rankChangeNum = previousRank - currentRank;
  if (rankChangeNum > 0) {
    rankChange = '+' + rankChangeNum + ' (improved)';
  } else if (rankChangeNum < 0) {
    rankChange = '' + rankChangeNum + ' (declined)';
  } else {
    rankChange = 'No change';
  }
}

return [{
  json: {
    date: metrics.date,
    domainRank: metrics.domainRank,
    organicTraffic: metrics.organicTraffic,
    organicKeywords: metrics.organicKeywords,
    keywords: metrics.keywords,
    previousRank: previousRank,
    rankChange: rankChange,
    rankChangeNum: rankChangeNum
  }
}];

const data = $('Calculate Rank Change').first().json;
const keywords = data.keywords || [];

const top5 = keywords
  .filter(k => k.keyword && k.searchVolume)
  .sort((a, b) => (parseInt(b.searchVolume) || 0) - (parseInt(a.searchVolume) || 0))
  .slice(0, 5);

const kwLines = top5.map((k, i) =>
  (i + 1) + '. *' + k.keyword + '* -- Pos: #' + k.position + ' | Vol: ' + Number(k.searchVolume).toLocaleString()
).join('\n');

const rankEmoji = data.rankChangeNum > 0 ? ':chart_with_upwards_trend:' : data.rankChangeNum < 0 ? ':chart_with_downwards_trend:' : ':left_right_arrow:';

const message = ':mag: *Guesty.com Weekly SEO Report -- ' + data.date + '*\n\n' +
  '*Domain Overview*\n' +
  '- Domain Rank: *#' + data.domainRank + '* ' + rankEmoji + ' (' + data.rankChange + ' vs last week)\n' +
  '- Organic Traffic: *' + Number(data.organicTraffic).toLocaleString() + '*\n' +
  '- Organic Keywords: *' + Number(data.organicKeywords).toLocaleString() + '*\n\n' +
  '*Top 5 Keywords by Search Volume*\n' +
  kwLines + '\n\n' +
  '_Full data logged to Google Sheets_';

return [{ json: { message: message } }];
